"use client";

import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Separator } from "@/components/ui/separator";
import {
  FormBase,
  FormInput,
} from "../../../../components/helisa/ui/form-field";
import { zodResolver } from "@hookform/resolvers/zod";
import { CircleAlert, Eye, EyeOff, LockKeyhole, Mail } from "lucide-react";
import { useEffect, useState } from "react";
import { useForm } from "react-hook-form";
import { z } from "zod";

const formSchema = z.object({
  email: z
    .string()
    .trim()
    .min(1, {
      message: "El correo electrónico es obligatorio.",
    })
    .email({
      message: "Ingresa un correo electrónico válido.",
    })
    .max(100, {
      message: "El correo electrónico no puede exceder 100 caracteres.",
    })
    .toLowerCase(),
  password: z.string().min(1, {
    message: "La contraseña es obligatoria.",
  }),
});

type FormData = z.infer<typeof formSchema>;

interface LoginProps {
  onSubmit: (data: FormData) => void | Promise<void | string>;
  onForgotPassword?: () => void;
  label?: string;
  description?: string;
  logoUrl?: string;
  termsUrl?: string;
  policyUrl?: string;
  error?: string;
}

const Login = ({
  onSubmit,
  onForgotPassword,
  label = "¡Bienvenido de nuevo!",
  description = "Ingrese sus credenciales para acceder de forma segura a su cuenta.",
  logoUrl,
  termsUrl,
  policyUrl,
  error,
}: LoginProps) => {
  const [showPassword, setShowPassword] = useState(false);
  const [backendError, setBackendError] = useState<string | undefined>(error);
  const [isSubmitting, setIsSubmitting] = useState(false);

  const form = useForm<FormData>({
    resolver: zodResolver(formSchema),
    defaultValues: {
      email: "",
      password: "",
    },
  });

  useEffect(() => {
    setBackendError(error);
    if (error) {
      form.reset({ email: "", password: "" });
    }
  }, [error, form]);

  const handleSubmit = async (data: FormData) => {
    setBackendError(undefined);
    setIsSubmitting(true);

    try {
      const result = await onSubmit(data);

      if (typeof result === "string") {
        setBackendError(result);
        form.reset({ email: "", password: "" });
      }
    } catch {
      setBackendError("Ocurrió un error inesperado. Intente nuevamente.");
      form.reset({ email: "", password: "" });
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <main className="flex min-h-screen items-center justify-center p-4">
      <section className="w-full max-w-sm min-w-[24rem] space-y-6">
        <article className="bg-card border rounded-2xl shadow-xl p-8">
          <header className="mb-6 text-center">
            {logoUrl ? (
              <img
                src={logoUrl}
                alt="Logo de la plataforma"
                draggable="false"
                className="mx-auto mb-4 h-16 w-auto object-contain select-none"
              />
            ) : (
              <div className="mx-auto mb-4 h-8 w-32 rounded-lg flex items-center justify-center">
                <span className="text-primary text-4xl font-bold select-none">
                  HELISA
                </span>
              </div>
            )}
            <h1 className="text-2xl font-extrabold">{label}</h1>
            <p className="text-sm text-muted-foreground mt-2">{description}</p>
          </header>
          <form
            className="space-y-6"
            onSubmit={form.handleSubmit(handleSubmit)}
          >
            {backendError && (
              <div className="flex items-center gap-1.5 bg-destructive/10 border border-destructive/50 text-destructive px-4 py-3 rounded-lg text-sm">
                <CircleAlert className="size-4" /> {backendError}
              </div>
            )}
            <FormInput
              control={form.control}
              name="email"
              label={
                <span className="flex items-center gap-2">
                  <Mail className="size-4" /> Correo electrónico
                </span>
              }
              type="email"
              placeholder="ejemplo@empresa.com"
              autoComplete="email"
            />

            <div className="space-y-2">
              <FormBase
                control={form.control}
                name="password"
                label={
                  <span className="flex items-center gap-2">
                    <LockKeyhole className="size-4" /> Contraseña
                  </span>
                }
              >
                {(field) => (
                  <div className="relative">
                    <Input
                      {...field}
                      type={showPassword ? "text" : "password"}
                      autoComplete="current-password"
                      placeholder="Su contraseña"
                      className="pr-10"
                    />
                    {field.value && (
                      <button
                        type="button"
                        onClick={() => setShowPassword(!showPassword)}
                        title={
                          showPassword
                            ? "Ocultar contraseña"
                            : "Mostrar contraseña"
                        }
                        className="absolute right-3 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-foreground transition-colors outline-none focus-visible:ring-2 focus-visible:ring-primary focus-visible:ring-offset-2 focus-visible:ring-offset-background rounded-sm"
                      >
                        {showPassword ? (
                          <EyeOff className="size-4" />
                        ) : (
                          <Eye className="size-4" />
                        )}
                      </button>
                    )}
                  </div>
                )}
              </FormBase>
            </div>
            <Button
              type="submit"
              className="w-full mt-2"
              disabled={isSubmitting}
            >
              {isSubmitting ? "Iniciando sesión..." : "Iniciar sesión"}
            </Button>
          </form>

          {onForgotPassword && (
            <>
              <Separator className="my-6" />
              <div className="flex items-center justify-center">
                <button
                  type="button"
                  onClick={onForgotPassword}
                  className="text-sm font-semibold text-primary hover:underline outline-none focus-visible:ring-2 focus-visible:ring-primary focus-visible:ring-offset-2 focus-visible:ring-offset-background flex items-center gap-1"
                >
                  ¿Olvidó su contraseña?
                </button>
              </div>
            </>
          )}
        </article>

        {termsUrl && policyUrl && (
          <footer className="text-center text-xs text-muted-foreground">
            <p>
              Al ingresar a la plataforma, acepta nuestros{" "}
              <a
                href={termsUrl}
                className="underline font-medium hover:text-foreground transition-colors"
                aria-label="Leer términos y condiciones"
              >
                Términos y Condiciones
              </a>{" "}
              y{" "}
              <a
                href={policyUrl}
                className="underline font-medium hover:text-foreground transition-colors"
                aria-label="Leer política de tratamientos de datos personales"
              >
                Política de Tratamientos de Datos Personales
              </a>
              .
            </p>
          </footer>
        )}
      </section>
    </main>
  );
};

export default Login;

"use client";

import { Button } from "@/components/ui/button";
import { ArrowLeft, ArrowRight } from "lucide-react";

interface RegisterProps {
  onSubmit: (e: React.FormEvent<HTMLFormElement>) => void | Promise<void>;
  onLoginClick?: () => void;
  loginLabel?: string;
  label?: string;
  description?: string;
  logoUrl?: string;
  submitLabel?: string;
  isSubmitting?: boolean;
  children: React.ReactNode;
}

const Register = ({
  onSubmit,
  onLoginClick,
  loginLabel = "Volver al inicio",
  label = "Crear una cuenta",
  description = "Regístrese para acceder a todas las funciones de la plataforma",
  logoUrl,
  submitLabel = "Crear cuenta",
  isSubmitting = false,
  children,
}: RegisterProps) => {
  return (
    <main className="flex h-screen w-screen">
      <section className="hidden lg:flex flex-1 h-full bg-neutral-100 items-center justify-center">
        <div className="text-center">
          {logoUrl ? (
            <img
              src={logoUrl}
              alt="Logo de la plataforma"
              draggable="false"
              className="h-32 w-auto object-contain select-none"
            />
          ) : (
            <div className="mx-auto flex items-center justify-center">
              <span className="text-primary text-6xl font-bold select-none">
                HELISA
              </span>
            </div>
          )}
        </div>
      </section>

      <section className="p-8 lg:p-0 flex-1 h-full flex items-center justify-center">
        <article className="w-full max-w-md">
          <header className="mb-6">
            {onLoginClick && (
              <button
                type="button"
                className="text-sm font-semibold text-primary hover:underline flex items-center gap-1 mb-6 "
                onClick={onLoginClick}
              >
                <ArrowLeft className="size-4" /> {loginLabel}
              </button>
            )}
            <h1 className="text-2xl font-extrabold">{label}</h1>
            <p className="text-sm text-muted-foreground mt-2">{description}</p>
          </header>
          <form className="space-y-5" onSubmit={onSubmit}>
            {children}
            <Button
              type="submit"
              className="w-full mt-2"
              disabled={isSubmitting}
            >
              {isSubmitting ? "Enviando..." : submitLabel}
              <ArrowRight className="size-4" />
            </Button>
          </form>
        </article>
      </section>
    </main>
  );
};

export default Register;

